<?php
declare(strict_types=1);require __DIR__.'/bootstrap.php';$viewer=vp3_require_viewer();$db=vp3_db();
$export=['exported_at'=>date(DATE_ATOM),'profile'=>$viewer,'clip_actions'=>[],'creator_follows'=>[],'show_follows'=>[],'watch_history'=>[]];
$queries=['clip_actions'=>'SELECT cp.publication_uuid,vca.action_type,vca.created_at FROM viewer_clip_actions vca JOIN clip_publications cp ON cp.id=vca.clip_publication_id WHERE vca.viewer_id=? ORDER BY vca.created_at DESC','creator_follows'=>'SELECT c.creator_uuid,c.display_name,vcf.created_at FROM viewer_creator_follows vcf JOIN creators c ON c.id=vcf.creator_id WHERE vcf.viewer_id=? ORDER BY vcf.created_at DESC','show_follows'=>'SELECT s.show_uuid,s.title,vsf.created_at FROM viewer_show_follows vsf JOIN shows s ON s.id=vsf.show_id WHERE vsf.viewer_id=? ORDER BY vsf.created_at DESC','watch_history'=>'SELECT cp.publication_uuid,cp.title,vwh.watch_seconds,vwh.completion_count,vwh.view_count,vwh.skipped_count,vwh.first_viewed_at,vwh.last_viewed_at FROM viewer_watch_history vwh JOIN clip_publications cp ON cp.id=vwh.clip_publication_id WHERE vwh.viewer_id=? ORDER BY vwh.last_viewed_at DESC'];foreach($queries as$key=>$sql){$stmt=$db->prepare($sql);$stmt->execute([(int)$viewer['id']]);$export[$key]=$stmt->fetchAll();}
header('Content-Type: application/json; charset=utf-8');header('Content-Disposition: attachment; filename="vp3-viewer-export-'.date('Ymd-His').'.json"');echo json_encode($export,JSON_PRETTY_PRINT|JSON_UNESCAPED_SLASHES|JSON_THROW_ON_ERROR);
